import { apiClient, unwrap } from '@linm-soft/common-components';
import type { BffResponse } from '@linm-soft/common-components';

export interface AccountingPeriodDto {
  id: string;
  month: number;
  year: number;
  status: string;
}

const BASE = '/accounting';

export const accountingEndpoint = {
  getPeriods: async (): Promise<AccountingPeriodDto[]> => {
    const res = await apiClient.get<BffResponse<AccountingPeriodDto[]>>(`${BASE}/periods`);
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },
};
